import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface MuscleGroup {
  name: string;
  exercises: number;
}

interface WorkoutSummary {
  exercisesCompleted: number;
  totalVolume: number;
  muscleGroups: MuscleGroup[];
}

export default function Widget() {
  const workoutData = response.data.summary as WorkoutSummary;
  const { exercisesCompleted, totalVolume, muscleGroups } = workoutData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Workout Summary
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {exercisesCompleted} Exercises
            </Typography>
            <Typography variant="body2" sx={{ color: '#F8FAFC', mt: 0.5 }}>
              Total Volume: {totalVolume.toLocaleString()} kg
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {muscleGroups.map((group, index) => (
              <Chip
                key={index}
                label={`${group.name}: ${group.exercises}`}
                sx={{ fontSize: '11px', color: '#F8FAFC', bgcolor: '#0D47A1', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
